const webhookData = $('Webhook').item.json;
const channel = webhookData.channel || 'LinkedIn';
const persona = webhookData.persona || 'Decision Maker';

const profileRow = $('Fetch Brand Profile').all()[0]?.json || {};
const brandData = profileRow.data_json || {};
const identity = brandData.identity || {};

const voiceRow = $('Fetch Voice Rules').all()[0]?.json || {};
const rules = voiceRow.rules_json || {};
const alwaysRules = (rules.always_rules || []).slice(0, 5).join('\n- ');
const neverRules = (rules.never_rules || []).slice(0, 5).join('\n- ');

// Extract top hooks from competitor videos
const videos = $('Fetch Competitor Hooks').all().map(i => i.json).slice(0, 20);
const competitorHooks = [];
videos.forEach(v => {
  if (v.analysis) {
    const m = v.analysis.match(/\*\*VISUAL:\*\*\s*(.+?)(?:\n|$)/);
    if (m && m[1].length > 10) competitorHooks.push(`- [${v.creator}, ${Math.round(v.views/1000)}K views] ${m[1].trim()}`);
  }
  if (v.newConcepts) {
    const matches = [...v.newConcepts.matchAll(/\*\*SPOKEN[^:]*:\*\*[^"]*"([^"]{15,120})"/g)];
    matches.slice(0, 2).forEach(m2 => competitorHooks.push(`- [${v.creator}, AI concept] "${m2[1].trim()}"`));
  }
});
const hooksContext = competitorHooks.slice(0, 8).join('\n') || '- No competitor hooks available yet (run pipeline first)';

const toneForChannel = (brandData.tone_by_channel || []).find(t => t.channel === channel) || {};

// Business verticals — payload takes precedence, fallback to brand_profiles.data_json.verticals.
const payloadSelected = webhookData.selected_vertical || null;
const payloadList = Array.isArray(webhookData.business_verticals) ? webhookData.business_verticals : [];
const profileList = Array.isArray(brandData.verticals) ? brandData.verticals : [];
const verticals = payloadList.length ? payloadList : profileList;

let verticalContext = '';
if (payloadSelected && payloadSelected.name) {
  verticalContext = `\n\nFOCUSED VERTICAL — write this brief specifically for the product/business unit "${payloadSelected.name}"${payloadSelected.desc ? ` (${payloadSelected.desc})` : ''}. Hook, body and CTA all anchor on this vertical. Do NOT cover the full portfolio.`;
} else if (verticals.length) {
  const list = verticals.map(v => `- ${v.name}${v.desc ? `: ${v.desc}` : ''}`).join('\n');
  verticalContext = `\n\nBUSINESS VERTICALS (full client portfolio — pick the single most relevant one for this ${channel} brief and anchor the hook on it):\n${list}`;
}

const systemPrompt = `You are an expert content strategist for ${identity.company_name || 'the brand'} in the ${identity.industry || 'B2B'} space.

Brand voice rules:
ALWAYS: ${alwaysRules || 'Be direct, specific, value-first'}
NEVER: ${neverRules || 'Use jargon, hype, or vague claims'}

Channel: ${channel}
Persona: ${persona}
Tone for ${channel}: ${toneForChannel.tone || 'Professional'} (${toneForChannel.formality || 'Mid-formal'})
${toneForChannel.examples ? `Examples: ${toneForChannel.examples}` : ''}${verticalContext}

Top hooks from competitor analysis (adapt these for the brand — do NOT copy):
${hooksContext}

Generate a content BRIEF with this structure (JSON):
{
  "hook": "Opening line — scroll-stopping, brand-voice compliant, under 15 words",
  "opening": "First paragraph — 1-2 sentences expanding the hook",
  "body": ["Point 1", "Point 2", "Point 3"],
  "cta": "Closing call-to-action — specific, no fluff",
  "hook_type": "Contrarian|Specific Number|How-We-Do-X|Open-Loop|Persona-Aware",
  "hook_score": 0-100,
  "vertical": "name of the vertical this brief anchors on (or empty if generic)",
  "channel": "${channel}",
  "persona": "${persona}"
}

Return ONLY valid JSON. No markdown, no explanation.`;

return [{ json: { systemPrompt, channel, persona, brand_id: $('Webhook').item.json.brand_id } }];

