const claudeResponse = $input.first().json;
const rawText = claudeResponse.content?.[0]?.text || '{}';

let brief;
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  brief = JSON.parse(jsonMatch ? jsonMatch[0] : rawText);
} catch (e) {
  brief = { hook: rawText.slice(0, 200), body: [], cta: '' };
}

const briefId = crypto.randomUUID();

return [{ json: {
  brief_id: briefId,
  brief,
  brand_id: $('Build Brief Prompt').item.json.brand_id,
  channel: $('Build Brief Prompt').item.json.channel,
  persona: $('Build Brief Prompt').item.json.persona,
} }];
